import math

def calculate_magnitude(vector):
    return math.sqrt(sum(x**2 for x in vector))

def calculate_distance(vector1, vector2):
    return calculate_magnitude([a - b for a, b in zip(vector1, vector2)])

def calculate_similarity(vector1, vector2):
    dot_product = sum(a * b for a, b in zip(vector1, vector2))
    magnitude1 = calculate_magnitude(vector1)
    magnitude2 = calculate_magnitude(vector2)
    return dot_product / (magnitude1 * magnitude2)

def calculate_vector_average(vectors):
    return [sum(x) / len(vectors) for x in zip(*vectors)]

def main():
    vector1 = [1, 2, 3]
    vector2 = [4, 5, 6]
    print("Magnitude of vector1:", calculate_magnitude(vector1))
    print("Magnitude of vector2:", calculate_magnitude(vector2))
    print("Distance between vector1 and vector2:", calculate_distance(vector1, vector2))
    print("Similarity between vector1 and vector2:", calculate_similarity(vector1, vector2))
